import React, { useEffect, useState } from 'react';
import axios from 'axios';

function App() {
  const [sanPhams, setSanPhams] = useState([]);

  useEffect(() => {
    axios.get('http://localhost:5000/api/san-pham')
      .then(res => setSanPhams(res.data))
      .catch(err => console.error("Lỗi kết nối API:", err));
  }, []);

  return (
    <div style={{ padding: '30px', backgroundColor: '#f4f7f6', minHeight: '100vh', fontFamily: 'Segoe UI' }}>
      <h1 style={{ textAlign: 'center', color: '#333' }}>🖥️ HỆ THỐNG BUILD PC TỰ CHỌN</h1>
      
      <div style={{ 
        display: 'grid', 
        gridTemplateColumns: 'repeat(auto-fill, minmax(280px, 1fr))', 
        gap: '25px',
        marginTop: '30px'
      }}>
        {sanPhams.map(item => (
          <div key={item._id} style={{ 
            backgroundColor: '#fff', 
            borderRadius: '15px', 
            overflow: 'hidden', 
            boxShadow: '0 4px 15px rgba(0,0,0,0.1)',
            transition: 'transform 0.2s'
          }}>
            {/* Phần hình ảnh */}
            <div style={{ width: '100%', height: '200px', backgroundColor: '#fff', display: 'flex', justifyContent: 'center', alignItems: 'center' }}>
                <img src={item.anh} alt={item.ten} style={{ maxWidth: '90%', maxHeight: '90%', objectFit: 'contain' }} />
            </div>

            {/* Phần thông tin */}
            <div style={{ padding: '20px' }}>
              <span style={{ fontSize: '12px', color: '#007bff', fontWeight: 'bold', textTransform: 'uppercase' }}>{item.loai}</span>
              <h3 style={{ margin: '10px 0', fontSize: '18px', color: '#2c3e50' }}>{item.ten}</h3>
              <p style={{ fontSize: '14px', color: '#7f8c8d' }}>{item.thongSo}</p>
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginTop: '15px' }}>
                <span style={{ fontSize: '20px', fontWeight: 'bold', color: '#e74c3c' }}>
                  {item.gia.toLocaleString()}đ
                </span>
                <button style={{ 
                  backgroundColor: '#2ecc71', 
                  color: '#fff', 
                  border: 'none', 
                  padding: '10px 15px', 
                  borderRadius: '8px', 
                  cursor: 'pointer',
                  fontWeight: 'bold'
                }}>
                  Chọn
                </button>
              </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

export default App;
